class Box {
private:
 int width, height, depth;
public:
 Box(int w=0, int h=0, int d=0) 
 : width(w), height(h), depth(d) {
 cout << "Constructor called" << endl;
 }

 Box(const Box& b) 
 : width(b.width), height(b.height), depth(b.depth) {
 cout << "Copy constructor called" << endl;
 }

 // RVO applies here - object constructed directly
 Box createBox() {
 return Box(10, 20, 30); // Temporary object
 }

 // NRVO applies here - named local variable
 Box createBox2() {
 Box b(5, 10, 15); // Named local variable
 return b; // NRVO may apply
 }
};

int main() {
 cout << "=== RVO Demo ===" << endl;
 Box b1 = createBox(); // C++17: Only constructor called

 cout << "\n=== NRVO Demo ===" << endl;
 Box b2 = createBox2(); // May use NRVO
}

class Vector {
private:
 int x, y;
public:
 Vector(int a=0, int b=0) : x(a), y(b) {}

 // Return const reference to member - safe
 const int& getX() const { return x; }
 const int& getY() const { return y; }

 // Non-const reference for chaining (operator overloading)
 Vector& setX(int val) { x = val; return *this; }
 Vector& setY(int val) { y = val; return *this; }

 // Static variable - safe to return reference
 static Vector& getOrigin() {
 static Vector origin(0, 0);
 return origin;
 }
};

// Friend function for stream operator - returns reference
ostream& operator<<(ostream& os, const Vector& v) {
 os << "(" << v.getX() << ", " << v.getY() << ")";
 return os; // Return stream reference for chaining
}

int main() {
 Vector v(5, 10);

 // Member access via const reference
 const int& rx = v.getX(); // No copy, read-only

 // Chaining via non-const reference
 v.setX(1).setY(2); // Method chaining

 // Stream operator chaining
 cout << v << endl;

 // Static reference
 Vector& origin = Vector::getOrigin();
}

// WRONG - Dangling reference!
int& badFunction() {
 int x = 10;
 return x; // DANGER: x is destroyed when function returns
}

// CORRECT - Return by value
int goodFunction() {
 int x = 10;
 return x; // Copy happens before x is destroyed
}

// WRONG - Dangling pointer
int* badPointerFunction() {
 int x = 10;
 return &x; // DANGER: x is destroyed
}

// CORRECT - Return by value or heap pointer
int* goodPointerFunction() {
 int* p = new int(10); // Heap allocation
 return p; // Caller must delete or use smart pointer
}

// Modern C++ - Use smart pointers
#include <memory>
std::unique_ptr<int> modernFunction() {
 return std::make_unique<int>(10); // Safe ownership transfer
}

int main() {
 // This causes undefined behavior!
 // int& ref = badFunction();

 // Safe usage
 int val = goodFunction();

 // Smart pointer - automatic memory management
 auto ptr = modernFunction();
}

class Buffer {
private:
 char* data;
 size_t size;
public:
 // Constructor
 Buffer(size_t s) : size(s) {
 data = new char[size];
 cout << "Constructor: Allocated " << size << " bytes" << endl;
 }

 // Copy Constructor - Deep Copy
 Buffer(const Buffer& other) : size(other.size) {
 data = new char[size];
 memcpy(data, other.data, size);
 cout << "Copy Constructor: Deep copy" << endl;
 }

 // Move Constructor - Transfer Ownership
 Buffer(Buffer&& other) noexcept : data(other.data), size(other.size) {
 other.data = nullptr;
 other.size = 0;
 cout << "Move Constructor: Ownership transferred" << endl;
 }

 // Destructor
 ~Buffer() {
 delete[] data;
 }

 // Getter returning const reference
 const size_t& getSize() const { return size; }
};

Buffer createBuffer(size_t size) {
 Buffer buf(size);
 return buf; // Move (if NRVO doesn't apply)
}

Buffer createBufferExplicit(size_t size) {
 Buffer buf(size);
 return std::move(buf); // Explicit move - same effect
}

int main() {
 cout << "=== Creating Buffer with RVO ===" << endl;
 Buffer b1 = createBuffer(100);

 cout << "\n=== Explicit Move ===" << endl;
 Buffer b2 = createBufferExplicit(200);

 cout << "\n=== Using Move ===" << endl;
 Buffer b3(50);
 Buffer b4 = std::move(b3); // b3 now empty
}

class Point {
private:
 int x, y;
public:
 Point(int px = 0, int py = 0) : x(px), y(py) {}

 // Getters
 int getX() const { return x; }
 int getY() const { return y; }

 // Setters - return reference for chaining
 Point& setX(int px) { x = px; return *this; }
 Point& setY(int py) { y = py; return *this; }

 // Addition operator - returns new Point by value
 Point operator+(const Point& other) const {
 return Point(x + other.x, y + other.y);
 }

 // Compound assignment - returns reference
 Point& operator+=(const Point& other) {
 x += other.x;
 y += other.y;
 return *this;
 }
};

// Stream insertion - returns ostream reference
ostream& operator<<(ostream& os, const Point& p) {
 os << "(" << p.getX() << ", " << p.getY() << ")";
 return os; // Enables: cout << p1 << p2 << endl;
}

// Stream extraction - returns istream reference
istream& operator>>(istream& is, Point& p) {
 int x, y;
 is >> x >> y;
 p.setX(x).setY(y);
 return is; // Enables: cin >> p1 >> p2;
}

int main() {
 Point p1(1, 2), p2(3, 4);

 // Method chaining
 p1.setX(10).setY(20);

 // Operator chaining
 Point p3 = p1 + p2; // Returns new Point
 p1 += p2; // p1 modified, returns reference

 // Stream chaining
 cout << "p1 = " << p1 << "\np2 = " << p2 << endl;

 // Input chaining
 // cin >> p1 >> p2;
}
